H10_data <- 
H10_data |> 
  mutate(
    H10_r2 = pmap(list(H10_a_model, data, family, response), r2_helper),
    H10_marginal = map_dbl(H10_r2, \(x) x$R2_marginal),
    H10_marginal = ifelse(H10_1a_sig, H10_marginal, NA)
  ) 
