::: {.cell filename='H11 formulas'}

```{.r .cell-code .hidden}
#| filename: H11 formulas
H11_form_1 <- lzMEDI ~ s(Time, k = 12) + s(Time, photoperiod.state, bs = "sz", k=12) + s(Time, sex, bs = "sz", k = 12) + s(Time, site, bs = "sz", k = 12) + s(Time, Id, bs = "fs") + s(Id_date, bs = "re")
H11_form_0 <- lzMEDI ~ s(Time, k = 12) + s(Time, photoperiod.state, bs = "sz", k=12) + s(Time, site, bs = "sz", k = 12) + s(Time, Id, bs = "fs") + s(Id_date, bs = "re")
```
:::


### Analysis

#### Base model (H11_1)


::: {.cell filename='Main model'}

```{.r .cell-code .hidden}
#| filename: Main model
H11_model_1 <- 
  bam(H11_form_1, 
      data = metric_participanthour, 
      discrete = TRUE,
      method = "fREML",
      nthreads = 10
      )

r1 <- start_value_rho(H11_model_1, 
                      plot=TRUE)
```

